# Plan: Extract Service Layer from Route Handlers

## Context

`src/routes/products.ts` and `src/routes/orders.ts` currently embed all business logic directly in Express route handlers. This mixes HTTP concerns (request parsing, response sending) with domain logic (filtering, validation, stock management, status transitions), making the code difficult to unit-test or reuse. The refactor extracts all business logic into `src/services/product-service.ts` and `src/services/order-service.ts`, leaving route handlers as thin HTTP adapters.

The existing integration tests in `tests/products.test.ts` and `tests/orders.test.ts` test through the HTTP layer via `supertest` and must continue to pass unchanged.

---

## Architecture Overview

```
src/
├── types.ts                    ← add new result/filter types
├── data.ts                     ← unchanged
├── app.ts                      ← unchanged
├── routes/
│   ├── products.ts             ← thin: parse → call service → send response
│   └── orders.ts               ← thin: parse → call service → send response
└── services/
    ├── product-service.ts      ← NEW: all product business logic
    └── order-service.ts        ← NEW: all order business logic
```

---

## Step 1 — Add types to `src/types.ts`

Add new interfaces/types at the bottom of the existing file. Do not modify existing exports.

```typescript
// Filter types
export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface OrderFilters {
  userId?: number;
  status?: string;
}

// Enriched return types
export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

// Discriminated union for operations that can fail with different HTTP status codes
export type ServiceResult<T> =
  | { success: true; data: T }
  | { success: false; status: number; error: string };
```

---

## Step 2 — Create `src/services/product-service.ts`

New file. Imports `products` array from `../data.js`. Exports three functions.

```typescript
import { products } from "../data.js";
import type {
  ProductFilters,
  ProductListResult,
  ProductDetail,
  ServiceResult,
} from "../types.js";

// Business logic: filter products and compute summary stats
export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }
  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }
  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

// Business logic: find product by ID and compute derived fields
export function getProductById(id: number): ProductDetail | null {
  const product = products.find((p) => p.id === id);
  if (!product) return null;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

// Business logic: validate and apply stock adjustment
export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);
  if (!product) {
    return { success: false, status: 404, error: "Product not found" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { success: false, status: 400, error: "Insufficient stock" };
  }

  product.stock = newStock;

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}
```

---

## Step 3 — Create `src/services/order-service.ts`

New file. Imports `orders`, `products`, `getNextOrderId` from `../data.js`. Exports four functions.

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type {
  Order,
  CreateOrderInput,
  OrderItem,
  OrderFilters,
  OrderListResult,
  EnrichedOrder,
  ServiceResult,
} from "../types.js";

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }
  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): EnrichedOrder | null {
  const order = orders.find((o) => o.id === id);
  if (!order) return null;

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return { ...item, productName: product?.name ?? "Unknown" };
  });

  return { ...order, items: enrichedItems };
}

export function createOrder(
  input: CreateOrderInput
): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return { success: false, status: 400, error: "userId and items are required" };
  }
  if (input.items.length === 0) {
    return { success: false, status: 400, error: "Order must have at least one item" };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return { success: false, status: 400, error: `Product ${item.productId} not found` };
    }
    if (item.quantity <= 0) {
      return { success: false, status: 400, error: "Quantity must be positive" };
    }
    if (product.stock < item.quantity) {
      return { success: false, status: 400, error: `Insufficient stock for ${product.name}` };
    }

    product.stock -= item.quantity;
    orderItems.push({ productId: product.id, quantity: item.quantity, price: product.price });
    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return { success: true, data: order };
}

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"] as const;

const STATUS_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    return { success: false, status: 404, error: "Order not found" };
  }
  if (!VALID_STATUSES.includes(status as typeof VALID_STATUSES[number])) {
    return {
      success: false,
      status: 400,
      error: `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
    };
  }
  if (!STATUS_TRANSITIONS[order.status]?.includes(status)) {
    return {
      success: false,
      status: 400,
      error: `Cannot transition from ${order.status} to ${status}`,
    };
  }

  order.status = status as Order["status"];
  return { success: true, data: order };
}
```

---

## Step 4 — Refactor `src/routes/products.ts`

Replace the entire file. Route handlers become thin: parse → call service → respond.

```typescript
import { Router } from "express";
import { listProducts, getProductById, adjustStock } from "../services/product-service.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" && !isNaN(parseFloat(minPrice)) ? parseFloat(minPrice) : undefined,
    maxPrice: typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice)) ? parseFloat(maxPrice) : undefined,
  });

  res.json(result);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = getProductById(id);

  if (!product) {
    res.status(404).json({ error: "Product not found" });
    return;
  }

  res.json(product);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  const result = adjustStock(id, adjustment);
  if (!result.success) {
    res.status(result.status).json({ error: result.error });
    return;
  }

  res.json(result.data);
});

export { router as productRouter };
```

---

## Step 5 — Refactor `src/routes/orders.ts`

Replace the entire file. Route handlers become thin: parse → call service → respond.

```typescript
import { Router } from "express";
import { listOrders, getOrderById, createOrder, updateOrderStatus } from "../services/order-service.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;

  const uid = typeof userId === "string" ? parseInt(userId, 10) : undefined;
  const result = listOrders({
    userId: uid !== undefined && !isNaN(uid) ? uid : undefined,
    status: typeof status === "string" ? status : undefined,
  });

  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = getOrderById(id);

  if (!order) {
    res.status(404).json({ error: "Order not found" });
    return;
  }

  res.json(order);
});

router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;
  const result = createOrder(input);

  if (!result.success) {
    res.status(result.status).json({ error: result.error });
    return;
  }

  res.status(201).json(result.data);
});

router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { status } = req.body as { status: string };
  const result = updateOrderStatus(id, status);

  if (!result.success) {
    res.status(result.status).json({ error: result.error });
    return;
  }

  res.json(result.data);
});

export { router as orderRouter };
```

---

## Files Modified

| File | Action |
|------|--------|
| `src/types.ts` | Add new interfaces/types (append only) |
| `src/services/product-service.ts` | **Create new** |
| `src/services/order-service.ts` | **Create new** |
| `src/routes/products.ts` | Replace with thin handlers |
| `src/routes/orders.ts` | Replace with thin handlers |
| `src/data.ts` | No changes |
| `src/app.ts` | No changes |
| `tests/products.test.ts` | No changes |
| `tests/orders.test.ts` | No changes |

---

## Key Design Decisions

- **`ServiceResult<T>` discriminated union**: Services return `{ success: true; data }` or `{ success: false; status; error }`. Route handlers check `result.success` and branch without try/catch. This keeps route handlers readable without exception handling boilerplate.
- **Simple null returns for single-failure lookups**: `getProductById` and `getOrderById` return `null` (not `ServiceResult`) since they only have one failure mode (not found → 404). Route handlers check for null directly.
- **No changes to data layer or tests**: The data arrays and `getNextOrderId` function in `src/data.ts` are unchanged. Integration tests continue to exercise the full HTTP stack.

---

## Verification

Run the existing test suite — all tests must pass:

```bash
npm test
```

Expected: all 12 tests across `products.test.ts` and `orders.test.ts` pass with no modifications to test files.

